from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    if not triples:
        return ""
    # The main subject is usually the airport or entity that appears most often as subject
    subject_counts = {}
    for t in triples:
        subject_counts[t.subject] = subject_counts.get(t.subject, 0) + 1
    main_subject = max(subject_counts, key=subject_counts.get)

    # Helper functions for common airport predicates
    def fmt_city_served(obj: str) -> str:
        return f"serves the city of {obj}"
    def fmt_elevation(obj: str) -> str:
        # assume metres unless feet is indicated in predicate name
        return f"is situated {obj} metres above sea level"
    def fmt_runway_length(obj: str) -> str:
        return f"its runway is {obj} metres long"
    def fmt_runway_name(obj: str) -> str:
        return f"its runway is named {obj}"
    def fmt_surface(obj: str, order: str) -> str:
        return f"its {order} runway surface is {obj}"
    def fmt_generic(pred: str, obj: str) -> str:
        pred_readable = pred.replace('_', ' ')
        return f"{pred_readable} {obj}"

    # Collect clauses, trying to group runway related info
    clauses = []
    runway_surface = {}
    runway_length = {}
    runway_name = {}
    for t in triples:
        p = t.predicate
        o = t.object
        if p == "cityServed":
            clauses.append(fmt_city_served(o))
        elif p == "elevationAboveTheSeaLevel":
            clauses.append(fmt_elevation(o))
        elif p == "runwayLength":
            clauses.append(fmt_runway_length(o))
        elif p == "runwayName":
            runway_name["main"] = o
        elif p.endswith("RunwaySurfaceType"):
            # extract order (e.g., 1st, 2nd, 3rd, 4th, 5th)
            order = p.split("RunwaySurfaceType")[0]
            runway_surface[order] = o
        elif p.endswith("RunwayLengthFeet"):
            # ignore feet version for simplicity, could convert if needed
            continue
        elif p.endswith("RunwayLengthMetre") or p.endswith("RunwayLength"):
            # already handled runwayLength above
            continue
        else:
            clauses.append(fmt_generic(p, o))

    # Add runway surface clauses in order
    for order in sorted(runway_surface.keys()):
        clauses.append(fmt_surface(runway_surface[order], order))

    # Add runway name if present
    if "main" in runway_name:
        clauses.append(fmt_runway_name(runway_name["main"]))

    # Build final sentence
    if not clauses:
        return f"{main_subject}."
    if len(clauses) == 1:
        return f"{main_subject} {clauses[0]}."
    # join with commas, last clause preceded by "and"
    *head, tail = clauses
    sentence = f"{main_subject} " + ", ".join(head) + f", and {tail}."
    return sentence

# EVOLVE-BLOCK-END

